head.script:
scwin.strCurrDate = $c.date.getServerDateTime();
scwin.strStartDate = $c.date.addDate(scwin.strCurrDate, 2);
scwin.strFirstDate = $c.date.getDateAddMonthDirection(scwin.strCurrDate, 0 , "F");  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)

scwin.hid_em_adptYm = scwin.strCurrDate.substring(0,6);

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//------------------------------------------------------------------------- 
scwin.onpageload = function() {
	acb_lux_madeYn.setValue("0"); //미생성
	acb_lux_selpchClsCd.setValue("1");
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    udc_rsltsStdDt.setInitDate(scwin.strCurrDate, scwin.strCurrDate);
    $c.gus.cfDisableBtn([cbx_chb_selpchItemCdYn]);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    ed_clntNo.setValue("");				//거래처번호
	txt_clntNm.setValue("");			//거래처명

	ed_em_selpchItemCd.setValue("");	//매출입항목
	txt_selpchItemNm.setValue("");		//매출입항목명

	ed_vehclNoCd.setValue("");
	txt_cond_vehclNo.setValue("");

	acb_lux_madeYn.setValue("0"); 		//미생성
	acb_lux_selpchClsCd.setValue("1");  //지급

    udc_rsltsStdDt.setInitDate(scwin.strCurrDate, scwin.strCurrDate);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    var rsltsStdDtStSub = ed_rsltsStdDtSt.getValue().substring(0,6);
	var rsltsStdDtEndSub = ed_rsltsStdDtEnd.getValue().substring(0,6);

    // 생성여부
	if(acb_lux_madeYn.getValue() == "1") {  // 조회/개별비용
		if(dma_condition.get("rsltsStdDtSt") == "" || dma_condition.get("rsltsStdDtEnd") == "") {
			$c.win.alert("실적기간은 필수 입력 항목입니다.");
			return false;
		}
		// FROM - TO 체크
        if (!$c.gus.cfIsAfterDate(ed_rsltsStdDtSt.getValue(), ed_rsltsStdDtEnd.getValue())) {
            $c.win.alert(MSG_CM_ERR_039);
            return false;
        }
	} else if(acb_lux_madeYn.getValue() == "2") {   // 전체차량생성
        if(ed_em_selpchItemCd.getValue() == "" || ed_em_selpchItemCd.getValue() == ""){
			$c.win.alert("매출입항목은 필수 입력 항목입니다.");
            return false;
        }

		if(dma_condition.get("rsltsStdDtSt") == "" ) {
			$c.win.alert("실적기간은 필수 입력 항목입니다.");
			return false;
		}	
	} else {    // 월고정비용생성
		if(dma_condition.get("rsltsStdDtSt") == "" ) {
			$c.win.alert("실적기간은 필수 입력 항목입니다.");
			return false;		
		}
	}

	//실적기간 체크
	if(rsltsStdDtStSub != rsltsStdDtEndSub) {
		$c.win.alert("실적기간 조회 기간은  같은 월 이어야 합니다.");
		return false;
	}

	dma_condition.set("adptYm", ed_rsltsStdDtSt.getValue().substring(0,6));

	if(cbx_chb_selpchItemCdYn.getValue() == 1) {
		dma_condition.set("selpchItemCdYn", 1);
	} else {
		dma_condition.set("selpchItemCdYn", 0);
	}

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        totalRows.setValue(ds_results.getRowCount());

        if (ds_results.getRowCount() == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        } else {
            gr_results.setFocusedCell(0, 0);
            if(acb_lux_madeYn.getValue() == "2") { //미생성_전체
                for(var i = 0; i < ds_results.getRowCount(); i++) {
                    ds_results.setCellData(i, "rsltsStdDt", ed_rsltsStdDtSt.getValue());
                    ds_results.setCellData(i, "selPchItemCd", em_selpchItemCd.getValue());
                    ds_results.setCellData(i, "selPchItemNm", txt_selpchItemNm.getValue());

                    if(ds_results.getCellData(i, "selpchClsCd") == "1") {
                        ds_results.setCellData(i, "clntNo", ds_results.getCellData(i, "sellClntNo"));
                        ds_results.setCellData(i, "clntNm", ds_results.getCellData(i, "sellClntNm"));
                        ds_results.setCellData(i, "clntAmt", ds_results.getCellData(i, "sellAmt"));
                        ds_results.setCellData(i, "clntVat", ds_results.getCellData(i, "sellVat"));
                    }		
                    else if(ds_results.getCellData(i, "selpchClsCd") == "2") {
                        ds_results.setCellData(i, "clntNo", ds_results.getCellData(i, "pchsClntNo"));
                        ds_results.setCellData(i, "clntNm", ds_results.getCellData(i, "pchsClntNm"));
                        ds_results.setCellData(i, "clntAmt", ds_results.getCellData(i, "pchsAmt"));
                        ds_results.setCellData(i, "clntVat", ds_results.getCellData(i, "pchsVat"));
                    }
                }
            } else {
                for(var i = 0; i < ds_results.getRowCount(); i++) {
                    if(ds_results.getCellData(i, "selpchClsCd") == "1") {
                        ds_results.setCellData(i, "clntNo", ds_results.getCellData(i, "sellClntNo"));
                        ds_results.setCellData(i, "clntNm", ds_results.getCellData(i, "sellClntNm"));
                        ds_results.setCellData(i, "clntAmt", ds_results.getCellData(i, "sellAmt"));
                        ds_results.setCellData(i, "clntVat", ds_results.getCellData(i, "sellVat"));
                    }
                    else if(ds_results.getCellData(i, "selpchClsCd") == "2") {
                        ds_results.setCellData(i, "clntNo", ds_results.getCellData(i, "pchsClntNo"));
                        ds_results.setCellData(i, "clntNm", ds_results.getCellData(i, "pchsClntNm"));
                        ds_results.setCellData(i, "clntAmt", ds_results.getCellData(i, "pchsAmt"));
                        ds_results.setCellData(i, "clntVat", ds_results.getCellData(i, "pchsVat"));
                    }
                }
            }

            ds_results.sort("vehclNo", 0);  // 차량번호별 정렬 (0: 오름차순, 1: 내림차순, 2: 정렬 취소)
            gr_results.refreshRow(0);
        }
    }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    var checkedCnt = 0;
    var validate = false;

   	for(var i = 0; i < ds_results.getRowCount(); i++) {

        var nPos = i + 1;
        if(ds_results.getCellData(i, "chk") == "1" ) {

			// update
            var rowStatus = ds_results.getRowStatus(i);
			if( rowStatus == 'U' ) { 

				if (ds_results.getCellData(i, "adptYm") == "") {
					//2023.08.02 적용년월은 조회기간 FROM년월 에서 입력한 실적일자 기준으로 셋팅으로 변경
					ds_results.setCellData(i, "adptYm", ds_results.getCellData(i, "rsltsStdDt").substring(0,6));
				} else {
                    if ( ds_results.getCellData(i, "adptYm") != ds_results.getCellData(i, "rsltsStdDt").substring(0,6) ) {
						$c.win.alert(nPos + "행의 실적일자는 " + ds_results.getCellData(i, "adptYm").substring(0,4) + "년" + ds_results.getCellData(i, "adptYm").substring(4,6) + "월 " +"적용년월 기간내여야 합니다.");
						return false;
					}
				}

				// 공제
				if(ds_results.getCellData(i, "selpchClsCd") == "1") {
					ds_results.setCellData(i, "sellYn", 1);		//매출여부
					ds_results.setCellData(i, "pchsYn", 0);		//매입여부
					ds_results.setCellData(i, "deductYn", 1);	//공제여부

					ds_results.setCellData(i, "sellClntNo", ds_results.getCellData(i, "clntNo"));	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ds_results.getCellData(i, "clntAmt")); 	//매출금액
					ds_results.setCellData(i, "sellVat", ds_results.getCellData(i, "clntVat")); 	//매출부가세

					ds_results.setCellData(i, "pchsClntNo", ""); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ""); 		//매입금액
					ds_results.setCellData(i, "pchsVat", ""); 		//매입부가세
				}
				//지급
				else if(ds_results.getCellData(i, "selpchClsCd") == "2") {
					ds_results.setCellData(i, "sellYn", 0);		//매출여부
					ds_results.setCellData(i, "pchsYn", 1);		//매입여부
					ds_results.setCellData(i, "deductYn", 0);	//공제여부

					ds_results.setCellData(i, "pchsClntNo", ds_results.getCellData(i, "clntNo")); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ds_results.getCellData(i, "clntAmt")); 	//매입금액
					ds_results.setCellData(i, "pchsVat", ds_results.getCellData(i, "clntVat")); 	//매입부가세

					ds_results.setCellData(i, "sellClntNo", "");	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ""); 		//매출금액
					ds_results.setCellData(i, "sellVat", ""); 		//매출부가세
				}

				if(ds_results.getCellData(i, "homeClntNo") == "") {
					ds_results.setCellData(i, "homeClntNo", ds_results.getCellData(i, "sellClntNo"));
				}

				if(ds_results.getCellData(i, "closeYn") == 1) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 마감처리되어 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 2) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 거래명세서생성 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 3) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 계산서생성 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 4) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 전표확정 상태여서 수정,삭제 할 수 없습니다.");
					return;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "vehclNo")) ) { 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량번호 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "homeClntNm")) ) { 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["소속거래처 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "clntNm")) ) { 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매니저 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}	

				if( $c.gus.cfIsNull(ds_results.getCellData(i, "rsltsStdDt")) ) { 
					$c.gus.cfAlertMsg(MSG_CM_ERR_002, ["실적일자 "]); //@은(는) 필수 입력 항목입니다
					return false;
				}

				validate = $c.date.isDate(ds_results.getCellData(i, "rsltsStdDt"));
				if(!validate){
					$c.win.alert(nPos + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
					return;
				}				
				checkedCnt++;
			}

			// insert
            if(rowStatus == 'C' ){ 
				ds_results.setCellData(i, "chk", "1");

				if (ds_results.getCellData(i, "adptYm") == "") {
					//2023.08.02 적용년월은 조회기간 FROM년월 에서 입력한 실적일자 기준으로 셋팅으로 변경
					ds_results.setCellData(i, "adptYm", ds_results.getCellData(i, "rsltsStdDt").substring(0,6));
				} else {
					if ( ds_results.getCellData(i, "adptYm") != ds_results.getCellData(i, "rsltsStdDt").substring(0,6) ) {
						$c.win.alert(nPos+"행의 실적일자는 " + ds_results.getCellData(i, "adptYm").substring(0,4) + "년" + ds_results.getCellData(i, "adptYm").substring(4,6) + "월 " +"적용년월 기간내여야 합니다.");
						return false;
					}
				}

				//공제
				if(ds_results.getCellData(i, "selpchClsCd") == "1") {
					ds_results.setCellData(i, "sellYn", 1);		//매출여부
					ds_results.setCellData(i, "pchsYn", 0);		//매입여부
					ds_results.setCellData(i, "deductYn", 1);	    //공제여부				
					ds_results.setCellData(i, "sellClntNo", ds_results.getCellData(i, "clntNo"));	//매출거래처번호 
					ds_results.setCellData(i, "sellAmt", ds_results.getCellData(i, "clntAmt")); 	//매출금액
					ds_results.setCellData(i, "sellVat", ds_results.getCellData(i, "clntVat")); 	//매출부가세
				}
				//지급
				else if(ds_results.getCellData(i, "selpchClsCd") == "2") {
					ds_results.setCellData(i, "sellYn", 0);		//매출여부
					ds_results.setCellData(i, "pchsYn", 1);		//매입여부
					ds_results.setCellData(i, "deductYn", 0);	    //공제여부
					ds_results.setCellData(i, "sellClntNo", ""); 		
					ds_results.setCellData(i, "pchsClntNo", ds_results.getCellData(i, "clntNo")); 	//매입거래처번호
					ds_results.setCellData(i, "pchsAmt", ds_results.getCellData(i, "clntAmt")); 	//매입금액
					ds_results.setCellData(i, "pchsVat", ds_results.getCellData(i, "clntVat")); 	//매입부가세
				}

				if(ds_results.getCellData(i, "homeClntNo") == "") {
					ds_results.setCellData(i, "homeClntNo", ds_results.getCellData(i, "sellClntNo"));
				}

				if(ds_results.getCellData(i, "vehclNo") == "") {
					$c.win.alert(nPos+"행의 차량번호는 필수 입력 항목 입니다.");
					return false;
				}

				if(ds_results.getCellData(i, "homeClntNm") == "") {
					$c.win.alert(nPos+"행의 소속거래처는 필수 입력 항목 입니다.");
					return false;
				}

				if(ds_results.getCellData(i, "clntNm") == "") {
					$c.win.alert(nPos+"행의 매니저는 필수 입력 항목 입니다.");
					return false;
				}

				if(ds_results.getCellData(i, "rsltsStdDt") == "") {
					$c.win.alert(nPos+"행의 실적일자는 필수 입력 항목 입니다.");
					return false;
				}

                validate = $c.date.isDate(ds_results.getCellData(i, "rsltsStdDt"));
				if(!validate){
					$c.win.alert(nPos + "번째 데이터의 실적일자는 유효한 날짜 형식이 아닙니다.");
					return;
				}	
				checkedCnt++;
			}

			// delete
            if(rowStatus == 'D' ){ 
				if(ds_results.getCellData(i, "closeYn") == 1) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 마감처리되어 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 2) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 거래명세서생성 상태여서 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 3) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 계산서생성 상태여서 삭제할 수 없습니다.");
					return;
				}

				if(ds_results.getCellData(i, "dcsnYn") == 4) {
					$c.gus.cfAlertMsg(nPos+"번째 실적은 전표확정 상태여서 삭제할 수 없습니다.");
					return;
				}

				checkedCnt++;
			}
		}
	}//for

	if(checkedCnt == 0) {
		$c.win.alert("체크된 데이터가 없습니다. 수정하려는 Row의 첫 열의 체크박스를 선택해 주십시오.");
		return false;
	}

    let confirm = await $c.win.confirm(MSG_CM_CRM_001); //저장하시겠습니까?
   	if (confirm) {
        $c.sbm.execute(sbm_save);
   	}
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
	    scwin.btn_retrieve_onclick();
    }
};

// 소속거래처
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp('CODE', 1, ed_clntNo, txt_clntNm, 'T', 'F');
};

scwin.udc_clntNo_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp('NAME', 1, ed_clntNo, txt_clntNm, 'T', 'F');
};

scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), txt_clntNm.getValue(), 'F', 'F');
};

// 매출입항목
scwin.udc_selpchItemCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp('CODE', 2, ed_em_selpchItemCd, txt_selpchItemNm, 'T', 'T');
};

scwin.udc_selpchItemCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp('NAME', 2, ed_em_selpchItemCd, txt_selpchItemNm, 'T', 'T');
};

scwin.udc_selpchItemCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_em_selpchItemCd.getValue(), txt_selpchItemNm.getValue(), 'F', 'T');
};

// 차량번호
scwin.udc_vehclNoCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp('CODE', 3, ed_vehclNoCd, txt_cond_vehclNo, 'T', 'T');
};

scwin.udc_vehclNoCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp('NAME', 3, ed_vehclNoCd, txt_cond_vehclNo, 'T', 'T');
};

scwin.udc_vehclNoCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_vehclNoCd.getValue(), txt_cond_vehclNo.getValue(), 'F', 'T');
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function(type, disGubun, codeObj, nameObj, pClose, pAllSearch) {

    var codeVal = (codeObj) ? codeObj.getValue() : '';
    var nameVal = (nameObj) ? nameObj.getValue() : '';

    if (codeObj) codeObj.setValue("");
    if (nameVal) nameObj.setValue("");

    if (type == 'CODE') {
        if (codeVal != '') scwin.f_openCommonPopUp(disGubun, codeVal, '', pClose, pAllSearch);
    } else if (type == 'NAME') {
        if (nameVal != '')  scwin.f_openCommonPopUp(disGubun, '', nameVal, pClose, pAllSearch);
    }
}

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch, row) {
