scwin.udc_clntNo_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) {
        ed_clntNo.setValue(rtnList[0]);     //코드
        txt_clntNm.setValue(rtnList[1]);    //명
        dma_condition.set("upperClntNo", rtnList[5]);
    }
};

scwin.udc_selpchItemCd_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) {
        ed_em_selpchItemCd.setValue(rtnList[0]);    //코드
        txt_selpchItemNm.setValue(rtnList[1]);      //명
    }
};

scwin.udc_vehclNoCd_callBackFunc = function (rtnList) {
     if( rtnList != null && rtnList[0] != "N/A" ) {
        ed_vehclNoCd.setValue(rtnList[0]);      //코드
        txt_cond_vehclNo.setValue(rtnList[1]);  //명
        ed_clntNo.setValue(rtnList[3]);         //코드
        txt_clntNm.setValue(rtnList[4]);        //명
    }
};

// Grid 차량번호
scwin.udc_comCode_Grid_Vehcl_callback = function(rtnList, rowIndex) {
    if (rtnList != null ) {
        ds_results.setCellData(rowIndex,"vehclNo", rtnList[1]);
        ds_results.setCellData(rowIndex,"homeClntNo", rtnList[3]);		
        ds_results.setCellData(rowIndex,"homeClntNm", rtnList[4]);	
        ds_results.setCellData(rowIndex,"clntNo", rtnList[5]);
        ds_results.setCellData(rowIndex,"clntNm", rtnList[6]);	
        ds_results.setCellData(rowIndex,"eqCd", rtnList[7]);

        gr_results.setFocusedCell(rowIndex, "rsltsStdDt", true);
    } else {
        ds_results.setCellData(rowIndex,"vehclNo", "");
        ds_results.setCellData(rowIndex,"homeClntNo", "");	
        ds_results.setCellData(rowIndex,"homeClntNm", "");
        ds_results.setCellData(rowIndex,"clntNo", "");
        ds_results.setCellData(rowIndex,"clntNm", "");	
        ds_results.setCellData(rowIndex,"eqCd", "");
    }
};

// Grid 소속거래처
scwin.udc_comCode_Grid_Clnt1_callback = function (rtnList, rowIndex) {
    if ( rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "homeClntNo", "homeClntNm");	
    } else {
        ds_results.setCellData(rowIndex,"homeClntNo", "");
        ds_results.setCellData(rowIndex,"homeClntNm", "");
    }
};

// Grid 매니저
scwin.udc_comCode_Grid_Clnt2_callback = function (rtnList, rowIndex) {
    if ( rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "clntNo", "clntNm");	
    }else{
        ds_results.setCellData(rowIndex,"clntNo", "");
        ds_results.setCellData(rowIndex,"clntNm", "");	
    }
};

// Grid 매출입항목
scwin.udc_comCode_Grid_SelpchItem_callback = function (rtnList, rowIndex) {
    if ( rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_results, rowIndex, "selpchItemCd", "selpchItemNm");	

        if( rtnList[2] == 0 ) {
            ds_results.setCellData(rowIndex,"taxnClsCd", "03");	
            ds_results.setCellData(rowIndex,"clntVat", 0);	
        } else {
            ds_results.setCellData(rowIndex,"taxnClsCd", "01");	
        }			
    } else {
        ds_results.setCellData(rowIndex,"selpchItemCd", "");	
        ds_results.setCellData(rowIndex,"selpchItemNm", "");	
    }
};

