// 행복사
//-------------------------------------------------------------------------
scwin.btn_copyRow_onclick = function (e) {
    var targetRow = ds_results.getRowPosition();

	scwin.f_addRow();

	var addedRow = ds_results.getRowPosition();
	// console.log("### btn_copyRow_onclick : "+targetRow);
    if( targetRow != null ) {
        ds_results.setCellData(addedRow, "chk", ds_results.getCellData(targetRow, "chk"));
        ds_results.setCellData(addedRow, "vehclNo", ds_results.getCellData(targetRow, "vehclNo"));			    //차량번호
    }
	ds_results.setCellData(addedRow, "homeClntNo", ds_results.getCellData(targetRow, "homeClntNo"));		//소속거래처번호
	ds_results.setCellData(addedRow, "homeClntNm", ds_results.getCellData(targetRow, "homeClntNm"));		//소속거래처명

	ds_results.setCellData(addedRow, "clntNo", ds_results.getCellData(targetRow, "clntNo"));			    //매니저번호
	ds_results.setCellData(addedRow, "clntNm", ds_results.getCellData(targetRow, "clntNm"));			    //매니저명
	ds_results.setCellData(addedRow, "pchsClntNo", ds_results.getCellData(targetRow, "pchsClntNo"));		//매입거래처번호
	ds_results.setCellData(addedRow, "pchsClntNm", ds_results.getCellData(targetRow, "pchsClntNm"));		//매입거래처명		

    if( targetRow != null ) {
        ds_results.setCellData(addedRow, "rsltsStdDt", ds_results.getCellData(targetRow, "rsltsStdDt"));		//실적일자
        ds_results.setCellData(addedRow, "selpchItemCd", ds_results.getCellData(targetRow, "selpchItemCd"));	//매출입코드
        ds_results.setCellData(addedRow, "selpchItemNm", ds_results.getCellData(targetRow, "selpchItemNm"));	//매출입항목명
        ds_results.setCellData(addedRow, "sellClntNo", ds_results.getCellData(targetRow, "sellClntNo"));		//매출거래처번호
        ds_results.setCellData(addedRow, "sellClntNm", ds_results.getCellData(targetRow, "sellClntNm"));		//매출거래처명
        ds_results.setCellData(addedRow, "selpchClsCd", ds_results.getCellData(targetRow, "selpchClsCd"));		//지급공제구분
    }

	ds_results.setCellData(addedRow, "clntAmt", ds_results.getCellData(targetRow, "clntAmt"));		        //금액
	ds_results.setCellData(addedRow, "sellAmt", ds_results.getCellData(targetRow, "sellAmt"));		        //매출금액	
	ds_results.setCellData(addedRow, "pchsAmt", ds_results.getCellData(targetRow, "pchsAmt"));		        //매입금액

	ds_results.setCellData(addedRow, "clntVat", ds_results.getCellData(targetRow, "clntVat"));		        //부가세
	ds_results.setCellData(addedRow, "sellVat", ds_results.getCellData(targetRow, "sellVat"));		        //매출부가세
	ds_results.setCellData(addedRow, "pchsVat", ds_results.getCellData(targetRow, "pchsVat"));		        //매입부가세

	ds_results.setCellData(addedRow, "taxnClsCd", ds_results.getCellData(targetRow, "taxnClsCd"));	        //과세구분
	ds_results.setCellData(addedRow, "hirecarCls", ds_results.getCellData(targetRow, "hirecarCls"));	    //용차구분
	ds_results.setCellData(addedRow, "dcsnYn", 1);		                                                    //확정여부 (1.미확정)
	ds_results.setCellData(addedRow, "odrNo", ds_results.getCellData(targetRow, "odrNo"));		            //매출입오더
	ds_results.setCellData(addedRow, "rmk", ds_results.getCellData(targetRow, "rmk"));			            //비고
	ds_results.setCellData(addedRow, "closeYn", 0);		                                                    //마감여부 (0.미마감)

// 	ds_results.setCellData(addedRow, "adptYm", (ds_results.getCellData(targetRow, "rsltsStdDt")).substring(0,6));
	ds_results.setCellData(addedRow, "rsltsSeq", ds_results.getCellData(targetRow, "rsltsSeq"));
	ds_results.setCellData(addedRow, "selpchItemSeq", ds_results.getCellData(targetRow, "selpchItemSeq"));
	ds_results.setCellData(addedRow, "eqCd", ds_results.getCellData(targetRow, "eqCd"));
	ds_results.setCellData(addedRow, "sellSeq", ds_results.getCellData(targetRow, "sellSeq"));
	ds_results.setCellData(addedRow, "pchsSeq", ds_results.getCellData(targetRow, "pchsSeq"));
	ds_results.setCellData(addedRow, "rsnCd", ds_results.getCellData(targetRow, "rsnCd"));
	ds_results.setCellData(addedRow, "sellYn", ds_results.getCellData(targetRow, "sellYn"));
	ds_results.setCellData(addedRow, "pchsYn", ds_results.getCellData(targetRow, "pchsYn"));
	ds_results.setCellData(addedRow, "deductYn", ds_results.getCellData(targetRow, "deductYn"));
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_addRow = function () {
	ds_results.insertRow();
    gr_results.setFocusedCell(ds_results.getRowCount()-1, 0);
	var row = ds_results.getRowPosition();

	ds_results.setCellData(row, "chk", "1");
	ds_results.setCellData(row, "rsltsStdDt", ed_rsltsStdDtSt.getValue());
	ds_results.setCellData(row, "selPchItemCd", ed_em_selpchItemCd.getValue());
	ds_results.setCellData(row, "selPchItemNm", txt_selpchItemNm.getValue());
	ds_results.setCellData(row, "sellClntNo", ed_clntNo.getValue());
	ds_results.setCellData(row, "sellClntNm", txt_clntNm.getValue());
	ds_results.setCellData(row, "selpchClsCd", acb_lux_selpchClsCd.getValue());
	ds_results.setCellData(row, "vehclNo", txt_cond_vehclNo.getValue());
	ds_results.setCellData(row, "dcsnYn", 1);	//확정여부 (1.미확정)
};

//-------------------------------------------------------------------------
// 행삭제
//------------------------------------------------------------------------- 
scwin.f_delete = function () {
	for( var i = 0; i < ds_results.getRowCount(); i++ ) {
		if( ds_results.getCellData(i, "chk") == "1" ) {
			ds_results.modifyRowStatus(i, 'D');
		}
	}
};

//-------------------------------------------------------------------------
// 금액일괄적용
//-------------------------------------------------------------------------
scwin.btn_adptAmt_onclick = function (e) {
    var clntAmt = 0;
	var clntVat = 0;
	var amtCnt = 0;
	var selpchClsCd = "";

	for(var i = 0; i < ds_results.getRowCount(); i++) {
		if(ds_results.getCellData(i, "chk") == "1") {
			//금액 
			if(ds_results.getCellData(i, "clntAmt") > 0 ) {
				clntAmt = ds_results.getCellData(i, "clntAmt");
				selpchClsCd = ds_results.getCellData(i, "selpchClsCd");
				amtCnt++;
			} else {
				ds_results.setCellData(i, "clntAmt", clntAmt);
			}

			//부가세
			if(ds_results.getCellData(i, "clntVat") > 0 ) {
				clntVat = ds_results.getCellData(i, "clntVat");
				selpchClsCd = ds_results.getCellData(i, "selpchClsCd");
				amtCnt++;
			} else {
				ds_results.setCellData(i, "clntVat", clntVat);
			}
			ds_results.setCellData(i, "selpchClsCd", selpchClsCd);
		}	
	}//for

	if(amtCnt == 0) {
		$c.win.alert("선택된 행들은 입력된 금액이 모두 0원 입니다.");
		return false;
	}
};

//-------------------------------------------------------------------------
// 실적일자일괄적용
//-------------------------------------------------------------------------
scwin.btn_adaptRsltsStdDt_onclick = function (e) {
    var chkCnt = 0;
	var rsltsStdDt = "";
	for(var i = 0; i < ds_results.getRowCount(); i++) {
		if(ds_results.getCellData(i, "chk") == "1") {
			if(ds_results.getCellData(i, "rsltsStdDt") != "" ) {
				rsltsStdDt = ds_results.getCellData(i, "rsltsStdDt");
				chkCnt++;
			} else {
				ds_results.setCellData(i, "rsltsStdDt", rsltsStdDt);
			}
		}
	}
	if(chkCnt == 0) {
		$c.win.alert("선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
		return false;
	}
};

//-------------------------------------------------------------------------
// 상세금액팝업
//-------------------------------------------------------------------------  
scwin.f_goDtlAmtPop = function (row) {
	var arrParam = new Array();
	var row = ds_results.getRowPosition(); 

    var data = {
          paramTitle  : "상세금액입력"
        , dtlMgntNo   : ds_results.getCellData(row, "dtlMgntNo")
        , callbackFn  : scwin.f_goDtlAmtPop_callBackFunc
    };

    var opts = {
          id : "smpPop"
        , popupName : "상세금액입력"
        , modal : true
        , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title : "Win pop"  //Layer pop
        , width : 300
        , height : 500
    };

    $c.win.openPopup("/ui/ja/dnja/workrslts/dnja_401_01_05p.xml", opts, data);
};

scwin.f_goDtlAmtPop_callBackFunc = function (rtnList) {
    if ( rtnList != null ) {
		if( rtnList.totDtlAmt != "" ) {
			ds_results.setCellData(ds_results.getRowPosition(), "clntAmt", rtnList.totDtlAmt);
			ds_results.setCellData(ds_results.getRowPosition(), "dtlMgntNo", rtnList.dtlMgntNo);
		}
	}
};

/*!-----------------------------------------------------------------------------
    G A U C E   C O M P O N E N T' S   E V E N T S  
------------------------------------------------------------------------------*/
scwin.gr_results_onafteredit = function (rowIndex, columnIndex, value) {
    var colId = gr_results.getColumnID(columnIndex);

    switch (colId)
    {
        case "vehclNo":
            var vehclNo = ds_results.getCellData(rowIndex, "vehclNo");
            scwin.f_openCommonPopUp(4, "", vehclNo, 'F', 'F', rowIndex);
            break;

        case "homeClntNm":
            var homeClntNm = ds_results.getCellData(rowIndex, "homeClntNm");
            scwin.f_openCommonPopUp(5, "", homeClntNm, 'F', 'F', rowIndex);
            break;

        case "clntNm":
            var clntNm = ds_results.getCellData(rowIndex, "clntNm");
            scwin.f_openCommonPopUp(6, "", clntNm, 'F', 'F', rowIndex);
            break;

        case "selpchItemCd":
            var selpchItemCd = ds_results.getCellData(rowIndex, "selpchItemCd");
            scwin.f_openCommonPopUp(7, selpchItemCd, "", 'F', 'F', rowIndex);
            break;

        case "clntAmt":     // 금액
            var amt = Number(ds_results.getCellData(rowIndex,"clntAmt"));
            ds_results.setCellData(rowIndex,"clntAmt", amt);

            var vat = $c.num.floor(amt * 0.1);
            if(ds_results.getCellData(rowIndex,"taxnClsCd") == "01") {
                ds_results.setCellData(rowIndex,"clntVat", vat);
                gr_results.setFocusedCell(rowIndex, "taxnClsCd");	
            }
            break;
        case "clntVat":         // 부가세
            var amt = Number(ds_results.getCellData(rowIndex,"clntVat"));
            ds_results.setCellData(rowIndex,"clntVat", amt);
            break;
        case "selpchClsCd":     // 지급공제구분
            var selpchClsCd = ds_results.getCellData(row, "selpchClsCd");

            if(selpchClsCd == "1"){
                if(ds_results.getCellData(rowIndex, "sellClntNo") == ""){
                    $c.win.alert("청구거래처를 등록해 주십시오.");
                    return false;
                }
            } else if(selpchClsCd == "2"){
                if(ds_results.getCellData(rowIndex, "pchsClntNo") == ""){
                    $c.win.alert("정산거래처를 등록해 주십시오.");                    
                    return false;
                }
            }
            break;
        case "deductYn":        // 없음

            ds_cond_deductPchsAmt.setJSON({
                adptYm          : ds_results.getCellData(rowIndex, "adptYm"),
                ed_vehclNoCd  : ds_results.getCellData(rowIndex, "vehclNo"),
                pchsClntNo      : ds_results.getCellData(rowIndex, "sellClntNo"), 
            });

            $c.sbm.execute(sbm_retrieve_deductPchsAmt);
            break;  
        case "taxnClsCd":       // 과세구분
            var amt = Number(ds_results.getCellData(rowIndex,"clntAmt"));
            var vat = $c.num.floor(amt * 0.1);

            // 과세구분
            if(ds_results.getCellData(rowIndex, "taxnClsCd") == "03"){ 
                ds_results.setCellData(rowIndex, "clntVat", 0);			
            }else {
                ds_results.setCellData(rowIndex, "clntVat", vat);
            }
            break;
        case "calculator":      // 매출입항목코드
                scwin.f_goDtlAmtPop();
                break;
        default:
            break;
    }
};

/* OnPopup(row,colid,data) */
scwin.gr_results_ontextimageclick = function (rowIndex, columnIndex) {
    let colid = gr_results.getColumnID(columnIndex);

    if (scwin.isOpenPopup != true) {
        if(colid == "vehclNo") {
            var vehclNo = ds_results.getCellData(rowIndex, "vehclNo");
            scwin.f_openCommonPopUp(4, "", vehclNo, 'F', 'F', rowIndex);
        }
        else if(colid == "homeClntNm") {
            var homeClntNm = ds_results.getCellData(rowIndex, "homeClntNm");
            scwin.f_openCommonPopUp(5, "", homeClntNm, 'F', 'F', rowIndex);
        }
        else if(colid == "clntNm") {
            var clntNm = ds_results.getCellData(rowIndex, "clntNm");
            scwin.f_openCommonPopUp(6, "", clntNm, 'F', 'F', rowIndex);
        }
        else if(colid == "selpchItemCd") {
            var selpchItemCd = ds_results.getCellData(rowIndex, "selpchItemCd");
            scwin.f_openCommonPopUp(7, selpchItemCd, "", 'F', 'F', rowIndex);
        }
        else if(colid == "calculator") { 
            scwin.f_goDtlAmtPop();
        }
    }
    setTimeout(function() {
        scwin.isOpenPopup = false;
    }, 100)
};

/* OnCloseUp() */
scwin.acb_lux_madeYn_onchange = function (info) {
    if(acb_lux_madeYn.getValue() == 1) {
		$c.gus.cfEnableBtnOnly([cbx_chb_selpchItemCdYn]);
	} else {
		$c.gus.cfDisableBtn([cbx_chb_selpchItemCdYn]);
	}
};

//-------------------------------------------------------------------------
// function name : f_Upload
// function desc : 엑셀업로드
//-------------------------------------------------------------------------
scwin.f_excelUpload = async function () {

    if( udc_topGrd.getUpExt() == "1" ) {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "header":"1",
            "type": "1",
            "startRowIndex":0,    // 시작row
            "skipSpace":"1",       // 공백무시 여부(1이면 무시 0이면 포함)
            "hidden":"0",           // 왼쪽히든값유무(미포함)
            "fillHidden":"0"        // 오른쪽히든값유무(무시)
        };
        ds_fileUp.removeAll();
        await $c.data.uploadGridViewCSV(gr_fileUp, options); // CSV 파일 업로드
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "type": "1",
            "headerExist":"1",
            "startRowIndex":0,  // 시작row
            "footerExist":"0"
        };
        ds_fileUp.removeAll();
        await $c.data.uploadGridViewExcel(gr_fileUp, options);
    }
};

// 업로드 완료 이벤트
scwin.gr_fileUp_onfilereadend = async function () {
    if (ds_fileUp.getRowCount() == 0) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if (await scwin.f_Upload()) {
        $c.gus.cfProgressWinClose();
        // await $c.win.alert("업로드작업이 완료되었습니다.");
    }
};

// ds_fileUp → ds_results 복사
scwin.f_Upload = async function () {

    ds_results.removeAll();
    let totalCnt = ds_fileUp.getRowCount();

    for (let i = 0; i < totalCnt; i++) {
        if (!ds_fileUp.getCellData(i, "rsltsStdDt")) continue;

        let nRow = ds_results.insertRow();
        ds_results.setRowPosition(nRow);

        ds_results.setCellData(nRow, "rsltsStdDt", ds_fileUp.getCellData(i, "rsltsStdDt"));

        ds_results.setCellData(nRow, "vehclNo", ds_fileUp.getCellData(i, "vehclNo"));            
        let rtn = await scwin.f_openCommonPopUp(4,  "", ds_fileUp.getCellData(i, "vehclNo"), "T", "T", i);
        // console.log("============>>rtn:"+rtn)       

        ds_results.setCellData(nRow, "homeClntNo", ds_fileUp.getCellData(i, "homeClntNo"));
        await scwin.f_openCommonPopUp(5, ds_fileUp.getCellData(i, "homeClntNo"), "", "T", "T", i);

        ds_results.setCellData(nRow, "clntNo", ds_fileUp.getCellData(i, "clntNo"));
        await scwin.f_openCommonPopUp(6, ds_fileUp.getCellData(i, "clntNo"), "", "T", "T", i);

        ds_results.setCellData(nRow, "selpchItemCd", ds_fileUp.getCellData(i, "selpchItemCd"));
        await scwin.f_openCommonPopUp(7, ds_fileUp.getCellData(i, "selpchItemCd"), "", "T", "T", i);

        ds_results.setCellData(nRow, "selpchClsCd", ds_fileUp.getCellData(i, "selpchClsCd"));
        ds_results.setCellData(nRow, "clntAmt", ds_fileUp.getCellData(i, "clntAmt"));
        ds_results.setCellData(nRow, "clntVat", ds_fileUp.getCellData(i, "clntVat"));
        ds_results.setCellData(nRow, "taxnClsCd", ds_fileUp.getCellData(i, "taxnClsCd"));
        ds_results.setCellData(nRow, "rmk", ds_fileUp.getCellData(i, "rmk"));
        ds_results.setCellData(nRow, "certiNo", ds_fileUp.getCellData(i, "certiNo"));
        ds_results.setCellData(nRow, "dcsnYn", 1);       
    }

    // ds_fileUp.removeAll();
    totalRows.setValue(ds_results.getRowCount());
};

scwin.gr_results_onbeforeedit = function (rowIndex, columnIndex, value) {
    var row = rowIndex;
    var colId = gr_results.getColumnID(columnIndex);
    if(ds_results.getCellData(row, "closeYn") == '1'){
        return false;
	}

    switch(colId)
    {
        case "clntVat":
            if (ds_results.getCellData(row, "taxnClsCd") != '01'){
                return false;
            }
            break;
        default:
            break;
    }
};

